module RefModule(
	input clk,
	input load,
	input shift_left,
	input shift_right,
	input rst_n,
	input [7:0] load_value,
	output reg [7:0] q);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
	if (!rst_n)
		q <= 8'b0;
	else if (load)
		q <= load_value;
	else if (shift_left)
		q <= q << 1;
	else if (shift_right)
		q <= q >> 1;
end

endmodule
